const DEFAULT_ADMIN_EMAIL = 'c.tonie2007@.com';
const AUTH_STORAGE_KEY = 'auth_state';
const AUTH_TTL_MS = 8 * 60 * 60 * 1000;

export function getAdminEmail() {
  return (process.env.REACT_APP_ADMIN_EMAIL || DEFAULT_ADMIN_EMAIL).trim().toLowerCase();
}

export function isAdminUser(user) {
  if (!user) {
    return false;
  }

  if (user.is_admin === true) {
    return true;
  }

  return String(user.email || '').trim().toLowerCase() === getAdminEmail();
}

export function setStoredAuth({ user, token, expiresInSeconds }) {
  const authState = {
    user,
    token,
    expiresAt: Date.now() + ((expiresInSeconds || AUTH_TTL_MS / 1000) * 1000),
  };

  localStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(authState));
}

export function clearStoredAuth() {
  localStorage.removeItem(AUTH_STORAGE_KEY);
}

export function getStoredAuth() {
  try {
    const rawUser = localStorage.getItem(AUTH_STORAGE_KEY);

    if (!rawUser) {
      return null;
    }

    const parsed = JSON.parse(rawUser);

    if (parsed && parsed.user && parsed.token && parsed.expiresAt) {
      if (Date.now() > parsed.expiresAt) {
        clearStoredAuth();
        return null;
      }

      return parsed;
    }

    return parsed;
  } catch (error) {
    clearStoredAuth();
    return null;
  }
}

export function getStoredUser() {
  return getStoredAuth()?.user || null;
}

export function getAuthToken() {
  return getStoredAuth()?.token || null;
}
